```jsx
const Input = ({ 
  size = 'md', 
  error = false, 
  disabled = false,
  placeholder = 'Entrez du texte...',
  type = 'text',
  id,
  name,
  value,
  onChange,
  onFocus,
  onBlur,
  ariaLabel,
  ariaDescribedBy,
  ...props 
}) => {
  // Mappage des valeurs de taille
  const sizeClasses = {
    sm: 'px-[var(--spacing-sm)] py-[var(--spacing-xs)] text-[var(--font-size-sm)] min-h-[32px]',
    md: 'px-[var(--spacing-sm)] py-[var(--spacing-sm)] text-[var(--font-size-md)] min-h-[40px]',
    lg: 'px-[var(--spacing-md)] py-[var(--spacing-sm)] text-[var(--font-size-lg)] min-h-[48px]'
  };

  // Déterminer les classes de bordure selon l'état
  const getBorderClass = () => {
    if (disabled) {
      return 'border-[var(--color-border-disabled)]';
    }
    if (error) {
      return 'border-[var(--color-danger-500)] focus:border-[var(--color-danger-500)]';
    }
    return 'border-[var(--color-border-default)] hover:border-[var(--color-border-strong)] focus:border-[var(--color-border-focus)]';
  };

  // Déterminer les classes de fond et texte
  const getBgClass = () => disabled 
    ? 'bg-[var(--color-bg-disabled)]' 
    : 'bg-[var(--color-bg-primary)]';

  const getTextClass = () => {
    if (disabled) {
      return 'text-[var(--color-text-disabled)]';
    }
    return 'text-[var(--color-text-primary)] placeholder:text-[var(--color-text-tertiary)]';
  };

