const Card = ({ 
  children, 
  variant = "md", 
  className = "",
  role = "article",
  ariaLabel = null 
}) => {
  // Mapping des variantes vers les variables CSS de padding
  const paddingMap = {
    sm: "var(--component-card-padding-sm)",
    md: "var(--component-card-padding-md)",
    lg: "var(--component-card-padding-lg)"
  };

  const paddingValue = paddingMap[variant] || paddingMap.md;

  return (
    <div
      role={role}
      aria-label={ariaLabel}
      className={`
        rounded-lg
        border
        bg-white
        transition-all
        duration-200
        hover:shadow-lg
        focus-within:ring-2
        focus-within:ring-offset-2
        focus-within:ring-blue-500
        ${className}
      `}
      style={{
        padding: paddingValue,
        borderColor: "var(--component-card-border)",
        backgroundColor: "var(--component-card-bg)",
        borderRadius: "var(--component-card-radius)",
        boxShadow: "var(--component-card-shadow)"
      }}
    >
      {children}
    </div>
